import{_ as s,o as a,c as i,ai as n}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Gateway Runbook","description":"","frontmatter":{"summary":"Runbook for the Gateway service, lifecycle, and operations","read_when":["Running or debugging the gateway process"],"title":"Gateway Runbook"},"headers":[],"relativePath":"gateway/index.md","filePath":"gateway/index.md","lastUpdated":null}'),t={name:"gateway/index.md"};function o(l,e,r,d,c,p){return a(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="gateway-service-runbook" tabindex="-1"><a class="header-anchor" href="#gateway-service-runbook">#</a> Gateway service runbook</h1><p>Last updated: 2025-12-09</p><h2 id="what-it-is" tabindex="-1"><a class="header-anchor" href="#what-it-is">#</a> What it is</h2><ul><li>The always-on process that owns the single Baileys/Telegram connection and the control/event plane.</li><li>Replaces the legacy <code>gateway</code> command. CLI entry point: <code>opensoul gateway</code>.</li><li>Runs until stopped; exits non-zero on fatal errors so the supervisor restarts it.</li></ul><h2 id="how-to-run-local" tabindex="-1"><a class="header-anchor" href="#how-to-run-local">#</a> How to run (local)</h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 18789</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># for full debug/trace logs in stdio:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 18789</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbose</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># if the port is busy, terminate listeners then start:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># dev loop (auto-reload on TS changes):</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway:watch</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><ul><li>Config hot reload watches <code>~/.opensoul/opensoul.json</code> (or <code>OPENSOUL_CONFIG_PATH</code>). <ul><li>Default mode: <code>gateway.reload.mode=&quot;hybrid&quot;</code> (hot-apply safe changes, restart on critical).</li><li>Hot reload uses in-process restart via <strong>SIGUSR1</strong> when needed.</li><li>Disable with <code>gateway.reload.mode=&quot;off&quot;</code>.</li></ul></li><li>Binds WebSocket control plane to <code>127.0.0.1:&lt;port&gt;</code> (default 18789).</li><li>The same port also serves HTTP (control UI, hooks, A2UI). Single-port multiplex. <ul><li>OpenAI Chat Completions (HTTP): <a href="/docs/gateway/openai-http-api"><code>/v1/chat/completions</code></a>.</li><li>OpenResponses (HTTP): <a href="/docs/gateway/openresponses-http-api"><code>/v1/responses</code></a>.</li><li>Tools Invoke (HTTP): <a href="/docs/gateway/tools-invoke-http-api"><code>/tools/invoke</code></a>.</li></ul></li><li>Starts a Canvas file server by default on <code>canvasHost.port</code> (default <code>18793</code>), serving <code>http://&lt;gateway-host&gt;:18793/__opensoul__/canvas/</code> from <code>~/.opensoul/workspace/canvas</code>. Disable with <code>canvasHost.enabled=false</code> or <code>OPENSOUL_SKIP_CANVAS_HOST=1</code>.</li><li>Logs to stdout; use launchd/systemd to keep it alive and rotate logs.</li><li>Pass <code>--verbose</code> to mirror debug logging (handshakes, req/res, events) from the log file into stdio when troubleshooting.</li><li><code>--force</code> uses <code>lsof</code> to find listeners on the chosen port, sends SIGTERM, logs what it killed, then starts the gateway (fails fast if <code>lsof</code> is missing).</li><li>If you run under a supervisor (launchd/systemd/mac app child-process mode), a stop/restart typically sends <strong>SIGTERM</strong>; older builds may surface this as <code>pnpm</code> <code>ELIFECYCLE</code> exit code <strong>143</strong> (SIGTERM), which is a normal shutdown, not a crash.</li><li><strong>SIGUSR1</strong> triggers an in-process restart when authorized (gateway tool/config apply/update, or enable <code>commands.restart</code> for manual restarts).</li><li>Gateway auth is required by default: set <code>gateway.auth.token</code> (or <code>OPENSOUL_GATEWAY_TOKEN</code>) or <code>gateway.auth.password</code>. Clients must send <code>connect.params.auth.token/password</code> unless using Tailscale Serve identity.</li><li>The wizard now generates a token by default, even on loopback.</li><li>Port precedence: <code>--port</code> &gt; <code>OPENSOUL_GATEWAY_PORT</code> &gt; <code>gateway.port</code> &gt; default <code>18789</code>.</li></ul><h2 id="remote-access" tabindex="-1"><a class="header-anchor" href="#remote-access">#</a> Remote access</h2><ul><li><p>Tailscale/VPN preferred; otherwise SSH tunnel:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 18789:127.0.0.1:18789</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@host</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>Clients then connect to <code>ws://127.0.0.1:18789</code> through the tunnel.</p></li><li><p>If a token is configured, clients must include it in <code>connect.params.auth.token</code> even over the tunnel.</p></li></ul><h2 id="multiple-gateways-same-host" tabindex="-1"><a class="header-anchor" href="#multiple-gateways-same-host">#</a> Multiple gateways (same host)</h2><p>Usually unnecessary: one Gateway can serve multiple messaging channels and agents. Use multiple Gateways only for redundancy or strict isolation (ex: rescue bot).</p><p>Supported if you isolate state + config and use unique ports. Full guide: <a href="/docs/gateway/multiple-gateways">Multiple gateways</a>.</p><p>Service names are profile-aware:</p><ul><li>macOS: <code>ai.opensoul.&lt;profile&gt;</code> (legacy <code>com.opensoul.*</code> may still exist)</li><li>Linux: <code>opensoul-gateway-&lt;profile&gt;.service</code></li><li>Windows: <code>OpenSoul Gateway (&lt;profile&gt;)</code></li></ul><p>Install metadata is embedded in the service config:</p><ul><li><code>OPENSOUL_SERVICE_MARKER=opensoul</code></li><li><code>OPENSOUL_SERVICE_KIND=gateway</code></li><li><code>OPENSOUL_SERVICE_VERSION=&lt;version&gt;</code></li></ul><p>Rescue-Bot Pattern: keep a second Gateway isolated with its own profile, state dir, workspace, and base port spacing. Full guide: <a href="/docs/gateway/multiple-gateways#rescue-bot-guide">Rescue-bot guide</a>.</p><h3 id="dev-profile-dev" tabindex="-1"><a class="header-anchor" href="#dev-profile-dev">#</a> Dev profile (<code>--dev</code>)</h3><p>Fast path: run a fully-isolated dev instance (config/state/workspace) without touching your primary setup.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --allow-unconfigured</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># then target the dev instance:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> health</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Defaults (can be overridden via env/flags/config):</p><ul><li><code>OPENSOUL_STATE_DIR=~/.opensoul-dev</code></li><li><code>OPENSOUL_CONFIG_PATH=~/.opensoul-dev/opensoul.json</code></li><li><code>OPENSOUL_GATEWAY_PORT=19001</code> (Gateway WS + HTTP)</li><li>browser control service port = <code>19003</code> (derived: <code>gateway.port+2</code>, loopback only)</li><li><code>canvasHost.port=19005</code> (derived: <code>gateway.port+4</code>)</li><li><code>agents.defaults.workspace</code> default becomes <code>~/.opensoul/workspace-dev</code> when you run <code>setup</code>/<code>onboard</code> under <code>--dev</code>.</li></ul><p>Derived ports (rules of thumb):</p><ul><li>Base port = <code>gateway.port</code> (or <code>OPENSOUL_GATEWAY_PORT</code> / <code>--port</code>)</li><li>browser control service port = base + 2 (loopback only)</li><li><code>canvasHost.port = base + 4</code> (or <code>OPENSOUL_CANVAS_HOST_PORT</code> / config override)</li><li>Browser profile CDP ports auto-allocate from <code>browser.controlPort + 9 .. + 108</code> (persisted per profile).</li></ul><p>Checklist per instance:</p><ul><li>unique <code>gateway.port</code></li><li>unique <code>OPENSOUL_CONFIG_PATH</code></li><li>unique <code>OPENSOUL_STATE_DIR</code></li><li>unique <code>agents.defaults.workspace</code></li><li>separate WhatsApp numbers (if using WA)</li></ul><p>Service install per profile:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --profile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --profile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rescue</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Example:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENSOUL_CONFIG_PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">~/.opensoul/a.json</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> OPENSOUL_STATE_DIR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">~/.opensoul-a</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 19001</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENSOUL_CONFIG_PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">~/.opensoul/b.json</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> OPENSOUL_STATE_DIR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">~/.opensoul-b</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 19002</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="protocol-operator-view" tabindex="-1"><a class="header-anchor" href="#protocol-operator-view">#</a> Protocol (operator view)</h2><ul><li>Full docs: <a href="/docs/gateway/protocol">Gateway protocol</a> and <a href="/docs/gateway/bridge-protocol">Bridge protocol (legacy)</a>.</li><li>Mandatory first frame from client: <code>req {type:&quot;req&quot;, id, method:&quot;connect&quot;, params:{minProtocol,maxProtocol,client:{id,displayName?,version,platform,deviceFamily?,modelIdentifier?,mode,instanceId?}, caps, auth?, locale?, userAgent? } }</code>.</li><li>Gateway replies <code>res {type:&quot;res&quot;, id, ok:true, payload:hello-ok }</code> (or <code>ok:false</code> with an error, then closes).</li><li>After handshake: <ul><li>Requests: <code>{type:&quot;req&quot;, id, method, params}</code> → <code>{type:&quot;res&quot;, id, ok, payload|error}</code></li><li>Events: <code>{type:&quot;event&quot;, event, payload, seq?, stateVersion?}</code></li></ul></li><li>Structured presence entries: <code>{host, ip, version, platform?, deviceFamily?, modelIdentifier?, mode, lastInputSeconds?, ts, reason?, tags?[], instanceId? }</code> (for WS clients, <code>instanceId</code> comes from <code>connect.client.instanceId</code>).</li><li><code>agent</code> responses are two-stage: first <code>res</code> ack <code>{runId,status:&quot;accepted&quot;}</code>, then a final <code>res</code> <code>{runId,status:&quot;ok&quot;|&quot;error&quot;,summary}</code> after the run finishes; streamed output arrives as <code>event:&quot;agent&quot;</code>.</li></ul><h2 id="methods-initial-set" tabindex="-1"><a class="header-anchor" href="#methods-initial-set">#</a> Methods (initial set)</h2><ul><li><code>health</code> — full health snapshot (same shape as <code>opensoul health --json</code>).</li><li><code>status</code> — short summary.</li><li><code>system-presence</code> — current presence list.</li><li><code>system-event</code> — post a presence/system note (structured).</li><li><code>send</code> — send a message via the active channel(s).</li><li><code>agent</code> — run an agent turn (streams events back on same connection).</li><li><code>node.list</code> — list paired + currently-connected nodes (includes <code>caps</code>, <code>deviceFamily</code>, <code>modelIdentifier</code>, <code>paired</code>, <code>connected</code>, and advertised <code>commands</code>).</li><li><code>node.describe</code> — describe a node (capabilities + supported <code>node.invoke</code> commands; works for paired nodes and for currently-connected unpaired nodes).</li><li><code>node.invoke</code> — invoke a command on a node (e.g. <code>canvas.*</code>, <code>camera.*</code>).</li><li><code>node.pair.*</code> — pairing lifecycle (<code>request</code>, <code>list</code>, <code>approve</code>, <code>reject</code>, <code>verify</code>).</li></ul><p>See also: <a href="/docs/concepts/presence">Presence</a> for how presence is produced/deduped and why a stable <code>client.instanceId</code> matters.</p><h2 id="events" tabindex="-1"><a class="header-anchor" href="#events">#</a> Events</h2><ul><li><code>agent</code> — streamed tool/output events from the agent run (seq-tagged).</li><li><code>presence</code> — presence updates (deltas with stateVersion) pushed to all connected clients.</li><li><code>tick</code> — periodic keepalive/no-op to confirm liveness.</li><li><code>shutdown</code> — Gateway is exiting; payload includes <code>reason</code> and optional <code>restartExpectedMs</code>. Clients should reconnect.</li></ul><h2 id="webchat-integration" tabindex="-1"><a class="header-anchor" href="#webchat-integration">#</a> WebChat integration</h2><ul><li>WebChat is a native SwiftUI UI that talks directly to the Gateway WebSocket for history, sends, abort, and events.</li><li>Remote use goes through the same SSH/Tailscale tunnel; if a gateway token is configured, the client includes it during <code>connect</code>.</li><li>macOS app connects via a single WS (shared connection); it hydrates presence from the initial snapshot and listens for <code>presence</code> events to update the UI.</li></ul><h2 id="typing-and-validation" tabindex="-1"><a class="header-anchor" href="#typing-and-validation">#</a> Typing and validation</h2><ul><li>Server validates every inbound frame with AJV against JSON Schema emitted from the protocol definitions.</li><li>Clients (TS/Swift) consume generated types (TS directly; Swift via the repo’s generator).</li><li>Protocol definitions are the source of truth; regenerate schema/models with: <ul><li><code>pnpm protocol:gen</code></li><li><code>pnpm protocol:gen:swift</code></li></ul></li></ul><h2 id="connection-snapshot" tabindex="-1"><a class="header-anchor" href="#connection-snapshot">#</a> Connection snapshot</h2><ul><li><code>hello-ok</code> includes a <code>snapshot</code> with <code>presence</code>, <code>health</code>, <code>stateVersion</code>, and <code>uptimeMs</code> plus <code>policy {maxPayload,maxBufferedBytes,tickIntervalMs}</code> so clients can render immediately without extra requests.</li><li><code>health</code>/<code>system-presence</code> remain available for manual refresh, but are not required at connect time.</li></ul><h2 id="error-codes-res-error-shape" tabindex="-1"><a class="header-anchor" href="#error-codes-res-error-shape">#</a> Error codes (res.error shape)</h2><ul><li>Errors use <code>{ code, message, details?, retryable?, retryAfterMs? }</code>.</li><li>Standard codes: <ul><li><code>NOT_LINKED</code> — WhatsApp not authenticated.</li><li><code>AGENT_TIMEOUT</code> — agent did not respond within the configured deadline.</li><li><code>INVALID_REQUEST</code> — schema/param validation failed.</li><li><code>UNAVAILABLE</code> — Gateway is shutting down or a dependency is unavailable.</li></ul></li></ul><h2 id="keepalive-behavior" tabindex="-1"><a class="header-anchor" href="#keepalive-behavior">#</a> Keepalive behavior</h2><ul><li><code>tick</code> events (or WS ping/pong) are emitted periodically so clients know the Gateway is alive even when no traffic occurs.</li><li>Send/agent acknowledgements remain separate responses; do not overload ticks for sends.</li></ul><h2 id="replay-gaps" tabindex="-1"><a class="header-anchor" href="#replay-gaps">#</a> Replay / gaps</h2><ul><li>Events are not replayed. Clients detect seq gaps and should refresh (<code>health</code> + <code>system-presence</code>) before continuing. WebChat and macOS clients now auto-refresh on gap.</li></ul><h2 id="supervision-macos-example" tabindex="-1"><a class="header-anchor" href="#supervision-macos-example">#</a> Supervision (macOS example)</h2><ul><li>Use launchd to keep the service alive: <ul><li>Program: path to <code>opensoul</code></li><li>Arguments: <code>gateway</code></li><li>KeepAlive: true</li><li>StandardOut/Err: file paths or <code>syslog</code></li></ul></li><li>On failure, launchd restarts; fatal misconfig should keep exiting so the operator notices.</li><li>LaunchAgents are per-user and require a logged-in session; for headless setups use a custom LaunchDaemon (not shipped). <ul><li><code>opensoul gateway install</code> writes <code>~/Library/LaunchAgents/ai.opensoul.gateway.plist</code> (or <code>ai.opensoul.&lt;profile&gt;.plist</code>; legacy <code>com.opensoul.*</code> is cleaned up).</li><li><code>opensoul doctor</code> audits the LaunchAgent config and can update it to current defaults.</li></ul></li></ul><h2 id="gateway-service-management-cli" tabindex="-1"><a class="header-anchor" href="#gateway-service-management-cli">#</a> Gateway service management (CLI)</h2><p>Use the Gateway CLI for install/start/stop/restart/status:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --follow</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Notes:</p><ul><li><code>gateway status</code> probes the Gateway RPC by default using the service’s resolved port/config (override with <code>--url</code>).</li><li><code>gateway status --deep</code> adds system-level scans (LaunchDaemons/system units).</li><li><code>gateway status --no-probe</code> skips the RPC probe (useful when networking is down).</li><li><code>gateway status --json</code> is stable for scripts.</li><li><code>gateway status</code> reports <strong>supervisor runtime</strong> (launchd/systemd running) separately from <strong>RPC reachability</strong> (WS connect + status RPC).</li><li><code>gateway status</code> prints config path + probe target to avoid “localhost vs LAN bind” confusion and profile mismatches.</li><li><code>gateway status</code> includes the last gateway error line when the service looks running but the port is closed.</li><li><code>logs</code> tails the Gateway file log via RPC (no manual <code>tail</code>/<code>grep</code> needed).</li><li>If other gateway-like services are detected, the CLI warns unless they are OpenSoul profile services. We still recommend <strong>one gateway per machine</strong> for most setups; use isolated profiles/ports for redundancy or a rescue bot. See <a href="/docs/gateway/multiple-gateways">Multiple gateways</a>. <ul><li>Cleanup: <code>opensoul gateway uninstall</code> (current service) and <code>opensoul doctor</code> (legacy migrations).</li></ul></li><li><code>gateway install</code> is a no-op when already installed; use <code>opensoul gateway install --force</code> to reinstall (profile/env/path changes).</li></ul><p>Bundled mac app:</p><ul><li>OpenSoul.app can bundle a Node-based gateway relay and install a per-user LaunchAgent labeled <code>ai.opensoul.gateway</code> (or <code>ai.opensoul.&lt;profile&gt;</code>; legacy <code>com.opensoul.*</code> labels still unload cleanly).</li><li>To stop it cleanly, use <code>opensoul gateway stop</code> (or <code>launchctl bootout gui/$UID/ai.opensoul.gateway</code>).</li><li>To restart, use <code>opensoul gateway restart</code> (or <code>launchctl kickstart -k gui/$UID/ai.opensoul.gateway</code>). <ul><li><code>launchctl</code> only works if the LaunchAgent is installed; otherwise use <code>opensoul gateway install</code> first.</li><li>Replace the label with <code>ai.opensoul.&lt;profile&gt;</code> when running a named profile.</li></ul></li></ul><h2 id="supervision-systemd-user-unit" tabindex="-1"><a class="header-anchor" href="#supervision-systemd-user-unit">#</a> Supervision (systemd user unit)</h2><p>OpenSoul installs a <strong>systemd user service</strong> by default on Linux/WSL2. We recommend user services for single-user machines (simpler env, per-user config). Use a <strong>system service</strong> for multi-user or always-on servers (no lingering required, shared supervision).</p><p><code>opensoul gateway install</code> writes the user unit. <code>opensoul doctor</code> audits the unit and can update it to match the current recommended defaults.</p><p>Create <code>~/.config/systemd/user/opensoul-gateway[-&lt;profile&gt;].service</code>:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Unit]</span></span>
<span class="line"><span>Description=OpenSoul Gateway (profile: &lt;profile&gt;, v&lt;version&gt;)</span></span>
<span class="line"><span>After=network-online.target</span></span>
<span class="line"><span>Wants=network-online.target</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Service]</span></span>
<span class="line"><span>ExecStart=/usr/local/bin/opensoul gateway --port 18789</span></span>
<span class="line"><span>Restart=always</span></span>
<span class="line"><span>RestartSec=5</span></span>
<span class="line"><span>Environment=OPENSOUL_GATEWAY_TOKEN=</span></span>
<span class="line"><span>WorkingDirectory=/home/youruser</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Install]</span></span>
<span class="line"><span>WantedBy=default.target</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p>Enable lingering (required so the user service survives logout/idle):</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo loginctl enable-linger youruser</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Onboarding runs this on Linux/WSL2 (may prompt for sudo; writes <code>/var/lib/systemd/linger</code>). Then enable the service:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>systemctl --user enable --now opensoul-gateway[-&lt;profile&gt;].service</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>Alternative (system service)</strong> - for always-on or multi-user servers, you can install a systemd <strong>system</strong> unit instead of a user unit (no lingering needed). Create <code>/etc/systemd/system/opensoul-gateway[-&lt;profile&gt;].service</code> (copy the unit above, switch <code>WantedBy=multi-user.target</code>, set <code>User=</code> + <code>WorkingDirectory=</code>), then:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo systemctl daemon-reload</span></span>
<span class="line"><span>sudo systemctl enable --now opensoul-gateway[-&lt;profile&gt;].service</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="windows-wsl2" tabindex="-1"><a class="header-anchor" href="#windows-wsl2">#</a> Windows (WSL2)</h2><p>Windows installs should use <strong>WSL2</strong> and follow the Linux systemd section above.</p><h2 id="operational-checks" tabindex="-1"><a class="header-anchor" href="#operational-checks">#</a> Operational checks</h2><ul><li>Liveness: open WS and send <code>req:connect</code> → expect <code>res</code> with <code>payload.type=&quot;hello-ok&quot;</code> (with snapshot).</li><li>Readiness: call <code>health</code> → expect <code>ok: true</code> and a linked channel in <code>linkChannel</code> (when applicable).</li><li>Debug: subscribe to <code>tick</code> and <code>presence</code> events; ensure <code>status</code> shows linked/auth age; presence entries show Gateway host and connected clients.</li></ul><h2 id="safety-guarantees" tabindex="-1"><a class="header-anchor" href="#safety-guarantees">#</a> Safety guarantees</h2><ul><li>Assume one Gateway per host by default; if you run multiple profiles, isolate ports/state and target the right instance.</li><li>No fallback to direct Baileys connections; if the Gateway is down, sends fail fast.</li><li>Non-connect first frames or malformed JSON are rejected and the socket is closed.</li><li>Graceful shutdown: emit <code>shutdown</code> event before closing; clients must handle close + reconnect.</li></ul><h2 id="cli-helpers" tabindex="-1"><a class="header-anchor" href="#cli-helpers">#</a> CLI helpers</h2><ul><li><code>opensoul gateway health|status</code> — request health/status over the Gateway WS.</li><li><code>opensoul message send --target &lt;num&gt; --message &quot;hi&quot; [--media ...]</code> — send via Gateway (idempotent for WhatsApp).</li><li><code>opensoul agent --message &quot;hi&quot; --to &lt;num&gt;</code> — run an agent turn (waits for final by default).</li><li><code>opensoul gateway call &lt;method&gt; --params &#39;{&quot;k&quot;:&quot;v&quot;}&#39;</code> — raw method invoker for debugging.</li><li><code>opensoul gateway stop|restart</code> — stop/restart the supervised gateway service (launchd/systemd).</li><li>Gateway helper subcommands assume a running gateway on <code>--url</code>; they no longer auto-spawn one.</li></ul><h2 id="migration-guidance" tabindex="-1"><a class="header-anchor" href="#migration-guidance">#</a> Migration guidance</h2><ul><li>Retire uses of <code>opensoul gateway</code> and the legacy TCP control port.</li><li>Update clients to speak the WS protocol with mandatory connect and structured presence.</li></ul>`,79)])])}const g=s(t,[["render",o]]);export{u as __pageData,g as default};
